import React, { useEffect, useState, useMemo, useContext } from "react";
import axios from "axios";
import GeneralContext from "./GeneralContext";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3002";

const Summary = () => {
  const { refreshKey } = useContext(GeneralContext);

  const [holdings, setHoldings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // ==========================
  // Fetch Holdings (Auto Refresh)
  // ==========================
  const fetchHoldings = async () => {
    try {
      setLoading(true);

      const response = await axios.get(`${API_URL}/allHoldings`);
      setHoldings(Array.isArray(response.data) ? response.data : []);
    } catch (err) {
      console.error("Error fetching summary data:", err);
      setError("Failed to load summary data.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHoldings();
  }, [refreshKey]); // 🔥 Auto update when order placed

  // ==========================
  // Owned Stocks Only
  // ==========================
  const ownedStocks = useMemo(() => {
    return holdings.filter((stock) => stock.qty > 0);
  }, [holdings]);

  // ==========================
  // Portfolio Calculations
  // ==========================
  const portfolio = useMemo(() => {
    const totalInvestment = ownedStocks.reduce(
      (acc, stock) => acc + stock.avg * stock.qty,
      0
    );

    const totalCurrentValue = ownedStocks.reduce(
      (acc, stock) => acc + stock.price * stock.qty,
      0
    );

    const totalPnL = totalCurrentValue - totalInvestment;
    const totalPnLPercent =
      totalInvestment > 0 ? (totalPnL / totalInvestment) * 100 : 0;

    return {
      totalInvestment,
      totalCurrentValue,
      totalPnL,
      totalPnLPercent,
    };
  }, [ownedStocks]);

  const formatCurrency = (value = 0) =>
    Number(value).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading summary...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <h3 className="title">Portfolio Summary</h3>

      {/* ===== Portfolio Cards ===== */}
      <div 
        className="summary-container" 
        style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(3, 1fr)', 
          gap: '24px',
          marginBottom: '30px'
        }}
      >
        <div 
          className="summary-box" 
          style={{ 
            minHeight: '180px', 
            padding: '24px', 
            display: 'flex', 
            flexDirection: 'column', 
            justifyContent: 'center',
            overflow: 'hidden'
          }}
        >
          <h5 style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', fontSize: '2rem', fontWeight: '600', margin: '0 0 8px 0' }}>
            ₹{formatCurrency(portfolio.totalInvestment)}
          </h5>
          <p style={{ color: '#94a3b8', fontSize: '0.9rem', margin: 0, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Total Investment</p>
        </div>

        <div 
          className="summary-box" 
          style={{ 
            minHeight: '180px', 
            padding: '24px', 
            display: 'flex', 
            flexDirection: 'column', 
            justifyContent: 'center',
            overflow: 'hidden'
          }}
        >
          <h5 style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', fontSize: '2rem', fontWeight: '600', margin: '0 0 8px 0' }}>
            ₹{formatCurrency(portfolio.totalCurrentValue)}
          </h5>
          <p style={{ color: '#94a3b8', fontSize: '0.9rem', margin: 0, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Current Value</p>
        </div>

        <div 
          className="summary-box" 
          style={{ 
            minHeight: '180px', 
            padding: '24px', 
            display: 'flex', 
            flexDirection: 'column', 
            justifyContent: 'center',
            overflow: 'hidden'
          }}
        >
          <div style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', margin: '0 0 8px 0' }}>
            <h5
              className={portfolio.totalPnL >= 0 ? "profit" : "loss"}
              style={{ display: 'inline', fontSize: '2rem', fontWeight: '600', marginRight: '8px' }}
            >
              ₹{formatCurrency(portfolio.totalPnL)}
            </h5>
            <span 
              className={portfolio.totalPnL >= 0 ? "profit" : "loss"}
              style={{ fontSize: '1.5rem', fontWeight: '500', opacity: 0.9 }}
            >
              ({portfolio.totalPnLPercent >= 0 ? '+' : ''}{portfolio.totalPnLPercent.toFixed(2)}%)
            </span>
          </div>
          <p style={{ color: '#94a3b8', fontSize: '0.9rem', margin: 0, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Total P&amp;L</p>
        </div>
      </div>

      {/* ===== Holdings Table ===== */}
      {ownedStocks.length === 0 ? (
        <p>No holdings yet.</p>
      ) : (
        <div className="order-table">
          <table>
            <thead>
              <tr>
                <th>Stock</th>
                <th>Qty</th>
                <th>Avg</th>
                <th>LTP</th>
                <th>Current Value</th>
                <th>P&amp;L</th>
              </tr>
            </thead>

            <tbody>
              {ownedStocks.map((stock) => {
                const currentValue = stock.price * stock.qty;
                const pnl =
                  currentValue - stock.avg * stock.qty;

                return (
                  <tr key={stock._id}>
                    <td>{stock.name}</td>
                    <td>{stock.qty}</td>
                    <td>₹{formatCurrency(stock.avg)}</td>
                    <td>₹{formatCurrency(stock.price)}</td>
                    <td>₹{formatCurrency(currentValue)}</td>
                    <td
                      className={pnl >= 0 ? "profit" : "loss"}
                    >
                      ₹{formatCurrency(pnl)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </>
  );
};

export default Summary;
